262	ngx_execute(ngx_cycle_t *cycle, ngx_exec_ctx_t *ctx)
263	{
264	    return ngx_spawn_process(cycle, ngx_execute_proc, ctx, ctx->name,
265	                             NGX_PROCESS_DETACHED);
